+// ========== CORREÇÃO DOS PEIXES E TARTARUGA ==========
+
+function initializeAnimations() {
+    // Selecionar todos os elementos animados
+    const fishes = document.querySelectorAll('.fish');
+    const turtle = document.querySelector('.turtle');
+    
+    // Função para resetar e iniciar animação de um elemento
+    function resetAndStartAnimation(element, isFish = true) {
+        if (!element) return;
+        
+        // Parar animação atual completamente
+        const currentAnimation = element.style.animation;
+        element.style.animation = 'none';
+        
+        // Forçar reflow (recalcular estilos do navegador)
+        // Isso é crítico para reiniciar animações CSS
+        void element.offsetHeight;
+        void element.offsetWidth;
+        
+        // Restaurar animação com configurações
+        if (isFish) {
+            // Duração aleatória entre 20 e 45 segundos para movimento mais natural
+            const randomDuration = Math.random() * 25 + 20;
+            // Atraso aleatório para não ficarem todos sincronizados
+            const randomDelay = Math.random() * 8;
+            element.style.animation = `swimLeft ${randomDuration}s linear infinite`;
+            element.style.animationDelay = `${randomDelay}s`;
+        } else {
+            element.style.animation = `swimTurtleLeft 40s linear infinite`;
+            element.style.animationDelay = '0s';
+        }
+    }
+    
+    // Resetar cada peixe individualmente
+    fishes.forEach((fish, index) => {
+        // Definir posição vertical aleatória se não tiver
+        if (!fish.style.top || fish.style.top === '') {
+            fish.style.top = `${Math.random() * 80 + 10}%`;
+        }
+        resetAndStartAnimation(fish, true);
+    });
+    
+    // Resetar tartaruga
+    if (turtle) {
+        resetAndStartAnimation(turtle, false);
+    }
+}
+
+// Forçar reinicialização quando a página carrega
+document.addEventListener('DOMContentLoaded', function() {
+    // Pequeno atraso para garantir que tudo está renderizado
+    setTimeout(initializeAnimations, 100);
+});
+
+// Recriar animações quando a página for restaurada do cache (ex: botão voltar)
+window.addEventListener('pageshow', function(event) {
+    if (event.persisted) {
+        setTimeout(initializeAnimations, 50);
+    }
+});
+
+// Recriar animações quando a janela for redimensionada
+let resizeTimeout;
+window.addEventListener('resize', function() {
+    clearTimeout(resizeTimeout);
+    resizeTimeout = setTimeout(function() {
+        initializeAnimations();
+    }, 200);
+});
+
+// Observar mudanças na visibilidade da página (ex: mudar de aba e voltar)
+document.addEventListener('visibilitychange', function() {
+    if (!document.hidden) {
+        setTimeout(initializeAnimations, 100);
+    }
+});
+
+// Salvar referência original do startGame para não perder funcionalidade
+const originalStartGame = window.startGame;
+if (originalStartGame) {
+    window.startGame = function() {
+        initializeAnimations();
+        return originalStartGame();
+    };
+}
+
+console.log('Animações dos peixes e tartaruga corrigidas!');
