// Perguntas e respostas
const questions = [
    {
        question: "",
        options: [
            "Promover a pesca predatória",
            "Conservar e usar sustentavelmente os oceanos, mares e recursos marinhos",
            "Aumentar a produção de plástico",
            "Desenvolver mais resorts à beira-mar"
        ],
        answer: 1,
        explanation: "A ODS 14 visa conservar e utilizar de forma sustentável os oceanos, mares e recursos marinhos para o desenvolvimento sustentável."
    },
    {
        question: "Qual material leva mais tempo para se decompor no oceano?",
        options: [
            "Papel",
            "Vidro",
            "Plástico",
            "Metal"
        ],
        answer: 2,
        explanation: "O plástico pode levar até 450 anos para se decompor no oceano, causando danos significativos à vida marinha."
    },
    {
        question: "O que significa a sigla ODS?",
        options: [
            "Objetivos de Desenvolvimento Sustentável",
            "Organização de Defesa Social",
            "Obras de Desenvolvimento Social",
            "Organização para Desenvolvimento Sustentável"
        ],
        answer: 0,
        explanation: "ODS significa Objetivos de Desenvolvimento Sustentável, uma agenda mundial com 17 objetivos adotados pela ONU em 2015."
    },
    {
        question: "Qual é a porcentagem aproximada de oxigênio da Terra produzido pelos oceanos?",
        options: [
            "10%",
            "30%",
            "50%",
            "70%"
        ],
        answer: 2,
        explanation: "Os oceanos produzem cerca de 50-70% do oxigênio da Terra através do fitoplâncton e outras plantas marinhas."
    },
    {
        question: "Qual destes itens NÃO deve ser colocado no lixo reciclável?",
        options: [
            "Garrafa PET",
            "Papelão",
            "Lâmpada fluorescente",
            "Lata de alumínio"
        ],
        answer: 2,
        explanation: "Lâmpadas fluorescentes contêm mercúrio e devem ser descartadas em pontos de coleta específicos, não no lixo reciclável comum."
    },
    {
        question: "Qual é o maior inimigo dos oceanos atualmente?",
        options: [
            "Navios de cruzeiro",
            "Poluição por plástico",
            "Pesca esportiva",
            "Aquecimento global"
        ],
        answer: 1,
        explanation: "A poluição por plástico é uma das maiores ameaças aos oceanos, com cerca de 8 milhões de toneladas de plástico entrando nos oceanos anualmente."
    },
    {
        question: "Qual destes materiais é reciclável?",
        options: [
            "Esponja de cozinha",
            "Copo de vidro quebrado",
            "Embalagem de salgadinho",
            "Garrafa de vidro"
        ],
        answer: 3,
        explanation: "Garrafas de vidro são 100% recicláveis e podem ser recicladas infinitamente sem perder qualidade."
    },
    {
        question: "Qual é o tempo médio de decomposição de uma sacola plástica no meio ambiente?",
        options: [
            "2 anos",
            "20 anos",
            "100 anos",
            "450 anos"
